VALUES
  ('judicial-f0899a01-moex-00106', 'judicial-f0899a01', 'judicial-f0899a01-moex-114-d1a761c9', 'sub-judicial-f0899a01-04', NULL, 'single_choice', '依國家賠償法規定，下列何者成立國家賠償？', '["水利灌溉設施因颱風之不可抗力遭毀致大水淹沒農田", "民眾騎機車進入經封閉之施工路段摔傷", "汽車駕駛人因道路坑洞致車輛受損", "市立醫院醫師診療行為有過失"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:45+00:00", "source_pdf_sha1": "9ce997984cf8", "answer_pdf_sha1": "68e95dc310c9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "202", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 48, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00107', 'judicial-f0899a01', 'judicial-f0899a01-moex-114-d1a761c9', 'sub-judicial-f0899a01-04', NULL, 'single_choice', '關於自然公物之國家賠償責任，下列敘述何者錯誤？', '["於開放之山域、水域等自然公物內之設施，經管理機關就使用該設施為適當之警告，而人民仍從事危險 性活動，得減輕或免除國家應負之損害賠償責任", "於開放之山域、水域等自然公物，經受委託管理之民間團體就使用該公物為適當之警告，而人民仍從事 危險性活動，國家不負損害賠償責任", "於開放之山域、水域等自然公物，經管理機關就使用該公物為適當之警告，而人民仍從事危險性活動， 得減輕國家應負之損害賠償責任", "於開放之山域、水域等自然公物內之設施，經受委託管理之民間團體就使用該設施為適當之標示，而人 民仍從事危險性活動，得減輕或免除國家應負之損害賠償責任"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:45+00:00", "source_pdf_sha1": "9ce997984cf8", "answer_pdf_sha1": "68e95dc310c9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "202", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00108', 'judicial-f0899a01', 'judicial-f0899a01-moex-114-d1a761c9', 'sub-judicial-f0899a01-04', NULL, 'single_choice', '關於公務員之國家賠償責任，下列敘述何者錯誤？', '["國家賠償法所稱公務員者，謂依法令從事於公務之人員", "公務員於執行職務行使公權力時，因故意或過失不法侵害人民自由或權利者，國家應負損害賠償責任", "公務員怠於執行職務，致人民自由或權利遭受損害者，國家亦應負損害賠償責任", "因公務員違法之國家賠償責任，公務員有具體輕過失時，賠償義務機關對之有求償權"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:45+00:00", "source_pdf_sha1": "9ce997984cf8", "answer_pdf_sha1": "68e95dc310c9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "202", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 50, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00109', 'judicial-f0899a01', 'judicial-f0899a01-moex-113-9a3b44c4', 'sub-judicial-f0899a01-01', NULL, 'essay', 'A 與眾人深夜飆車競駛，被警察以現行犯逮捕。凌晨 2 時許，A被帶至
警局，員警先告知 A可拒絕夜間詢問，因 A明確表示同意詢問，警員開
始製作筆錄。警詢經過 1 小時，A頻頻打呵欠，並說「非常睏」、「忍不
住了」。警察為了不讓 A 入睡，持續拍觸 A 肩膀，A 遂在半睡半醒之間
作出不利之自白。請分析其自白有無證據能力？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:45+00:00", "source_pdf_sha1": "619dbf334e12", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "202", "s": "0513", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑事訴訟法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00110', 'judicial-f0899a01', 'judicial-f0899a01-moex-113-9a3b44c4', 'sub-judicial-f0899a01-01', NULL, 'essay', 'A是鄉公所課員，涉嫌透過 B收賄。警察受理某人告發，為調查案情始
末，以證人身分通知 B 到警局接受詢問，有製作不利於 A 之警詢筆錄
（下稱筆錄）。檢察官以 A犯違背職務收賄罪提起公訴。地方法院審判期
日證據調查時，審判長未傳喚 B到庭，僅提示並宣讀該筆錄，並訊問 A
是否同意筆錄有證據能力，A 表示「沒有意見」。地方法院勘驗詢問錄
音，審酌筆錄製作過程並無不法情事，遂採為 A有罪判決之證據。A之
後上訴高等法院，改而主張筆錄無證據能力。請依實務見解分析A之主
張有無理由？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:45+00:00", "source_pdf_sha1": "619dbf334e12", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "202", "s": "0513", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑事訴訟法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00111', 'judicial-f0899a01', 'judicial-f0899a01-moex-113-9a3b44c4', 'sub-judicial-f0899a01-01', NULL, 'essay', 'A、B 是中華民國人民。A 得知 B 因違反銀行法案件被通緝而藏匿在泰
國，欲返國又恐遭羈押，遂基於詐欺取財之犯意，在泰國對 B佯稱熟識
我國司法人員，可安排返國歸案而不被羈押，致B 陷於錯誤，在泰國陸
續支付 A美金共4 萬元。嗣 B從泰國搭機回臺灣，於桃園國際機場入境
後為法務部調查局人員逮捕歸案，方知受騙而報案。檢察官對 A提起公
訴，法院以 A於我國領域外犯普通詐欺罪，無我國刑法之適用，認無行
言詞辯論必要，逕諭知不受理判決。請分析法院審判是否合法？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:45+00:00", "source_pdf_sha1": "619dbf334e12", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "202", "s": "0513", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑事訴訟法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00112', 'judicial-f0899a01', 'judicial-f0899a01-moex-113-9a3b44c4', 'sub-judicial-f0899a01-01', NULL, 'essay', '被告 A因涉犯組織犯罪罪名，於偵查中經檢察官向地方法院聲請裁定羈
押獲准。A 對該羈押裁定並無意願提起抗告，惟 A 之配偶 B 認為 A 受
冤枉，主動為 A之利益提出抗告。請分析抗告是否合法？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:45+00:00", "source_pdf_sha1": "619dbf334e12", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "202", "s": "0513", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑事訴訟法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00113', 'judicial-f0899a01', 'judicial-f0899a01-moex-113-e2754278', 'sub-judicial-f0899a01-02', NULL, 'single_choice', '依司法院釋字第 777 號，關於刑法第 185 條之4 肇事逃逸罪，其中有關「肇事」部分，違反下列何項原 則？', '["罪刑相當原則", "法律保留原則", "罪疑惟輕原則", "法律明確性原則"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:45+00:00", "source_pdf_sha1": "a525ee14afef", "answer_pdf_sha1": "fa3e7a8162d0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "202", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00114', 'judicial-f0899a01', 'judicial-f0899a01-moex-113-e2754278', 'sub-judicial-f0899a01-02', NULL, 'single_choice', '有關刑法地之效力，下列敘述何者正確？', '["犯罪之結果在我國領域內者，適用我國刑法", "犯罪行為與結果皆在我國領域內者，始適用我國刑法", "外國人於我國領域內犯罪，不適用我國刑法", "外國人於我國領域外對於我國人民犯罪，一律不適用我國刑法"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:45+00:00", "source_pdf_sha1": "a525ee14afef", "answer_pdf_sha1": "fa3e7a8162d0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "202", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00115', 'judicial-f0899a01', 'judicial-f0899a01-moex-113-e2754278', 'sub-judicial-f0899a01-02', NULL, 'single_choice', '有關刑法就犯罪成立之要件，於行為後法律有變更時，採取何種原則？', '["從舊原則", "從新原則", "從重原則", "從舊從輕原則"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:45+00:00", "source_pdf_sha1": "a525ee14afef", "answer_pdf_sha1": "fa3e7a8162d0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "202", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL)
